// Extract HTML from Claude API response
const response = $input.first().json;
const topic = $('Get Next Topic').first().json;

let html = '';

// The response is from the Messages API
if (response.content && response.content.length > 0) {
  html = response.content[0].text;
}

// Clean up if Claude wrapped it in code fences
html = html.replace(/^```html\n?/i, '').replace(/\n?```$/i, '');
html = html.replace(/^```\n?/, '').replace(/\n?```$/, '');
html = html.trim();

// Validate it starts with DOCTYPE
if (!html.startsWith('<!DOCTYPE') && !html.startsWith('<!doctype')) {
  // Try to find DOCTYPE in the response
  const doctypeIndex = html.indexOf('<!DOCTYPE');
  if (doctypeIndex === -1) {
    const doctypeIndexLower = html.indexOf('<!doctype');
    if (doctypeIndexLower !== -1) {
      html = html.substring(doctypeIndexLower);
    }
  } else {
    html = html.substring(doctypeIndex);
  }
}

return [{
  json: {
    html: html,
    slug: topic.slug,
    title: topic.title,
    tag: topic.tag,
    tagClass: topic.tagClass,
    metaDescription: topic.metaDescription,
    readTime: topic.readTime,
    publishDate: topic.publishDate,
    isoDate: topic.isoDate,
    filename: topic.filename
  }
}];

// Update blog.html with new article card
const blogResponse = $('Get blog.html').first().json;
const article = $('Extract HTML').first().json;

// Decode blog.html content from base64
const blogContent = Buffer.from(blogResponse.content, 'base64').toString('utf-8');
const blogSha = blogResponse.sha;

// Build the new card HTML
const newCard = `
    <!-- Auto-generated: ${article.slug} -->
    <a href="/blog/${article.slug}" class="card reveal">
      <div class="card-tag ${article.tagClass}">${article.tag}</div>
      <h3>${article.title}</h3>
      <div class="card-desc">${article.metaDescription}</div>
      <div class="card-bottom">
        <span>${article.publishDate}</span>
        <span>&#128337; ${article.readTime}</span>
      </div>
    </a>`;

// Insert new card before the closing </div> of the grid
// Find the position: before the first </div> that follows the last </a> card
const gridEndMarker = '\n  </div>\n</div>\n\n<!-- CTA -->';
const updatedBlog = blogContent.replace(
  gridEndMarker,
  `${newCard}\n\n  </div>\n</div>\n\n<!-- CTA -->`
);

return [{
  json: {
    updatedBlogHtml: updatedBlog,
    blogSha: blogSha
  }
}];

// Update sitemap.xml with new article URL
const sitemapResponse = $('Get sitemap.xml').first().json;
const article = $('Extract HTML').first().json;

// Decode sitemap content from base64
const sitemapContent = Buffer.from(sitemapResponse.content, 'base64').toString('utf-8');
const sitemapSha = sitemapResponse.sha;

// Build new URL entry
const newUrlEntry = `  <url>
    <loc>https://www.csbconcepts.com/blog/${article.slug}</loc>
    <lastmod>${article.isoDate}</lastmod>
    <changefreq>monthly</changefreq>
    <priority>0.8</priority>
  </url>`;

// Insert before the <!-- Legal --> comment
const updatedSitemap = sitemapContent.replace(
  '\n  <!-- Legal -->',
  `\n  ${newUrlEntry}\n\n  <!-- Legal -->`
);

return [{
  json: {
    updatedSitemapXml: updatedSitemap,
    sitemapSha: sitemapSha
  }
}];

// Update vercel.json with new rewrite rule
const vercelResponse = $('Get vercel.json').first().json;
const article = $('Extract HTML').first().json;

// Decode vercel.json content from base64
const vercelContent = Buffer.from(vercelResponse.content, 'base64').toString('utf-8');
const vercelSha = vercelResponse.sha;

// Parse the JSON
const vercelConfig = JSON.parse(vercelContent);

// Add new rewrite rule for the blog article (before the booking redirect)
const newRewrite = {
  source: `/blog/${article.slug}`,
  destination: `/blog/${article.slug}.html`
};

// Check if rewrite already exists
const exists = vercelConfig.rewrites.some(r => r.source === newRewrite.source);
if (!exists) {
  // Insert before the last rewrite (booking)
  const bookingIndex = vercelConfig.rewrites.findIndex(r => r.source === '/booking');
  if (bookingIndex !== -1) {
    vercelConfig.rewrites.splice(bookingIndex, 0, newRewrite);
  } else {
    vercelConfig.rewrites.push(newRewrite);
  }
}

const updatedVercel = JSON.stringify(vercelConfig, null, 2) + '\n';

return [{
  json: {
    updatedVercelJson: updatedVercel,
    vercelSha: vercelSha
  }
}];

